### 3-1. User 도메인 (`catalog = "maum"`)

**파일 경로:** `domain/src/main/kotlin/com/maum/backend/entity/user/`

```kotlin
// UserEntity.kt
@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(unique = true, nullable = false, length = 20)
    val phoneNumber: String,

    @Column(nullable = false)
    var status: Int = UserStatus.ACTIVE.value,    // 0:ACTIVE, 1:INACTIVE, 2:BANNED

    @Column(nullable = false)
    var role: Int = UserRole.USER.value,          // 0:USER, 1:ADMIN

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),

    var deletedAt: LocalDateTime? = null,
) {
    enum class UserStatus(val value: Int) {
        ACTIVE(0), INACTIVE(1), BANNED(2);
        companion object { fun fromValue(v: Int) = entries.first { it.value == v } }
    }
    enum class UserRole(val value: Int) {
        USER(0), ADMIN(1);
        companion object { fun fromValue(v: Int) = entries.first { it.value == v } }
    }
}
```

