### 4-2. user.graphqls

```graphql
type User {
    id: ID!
    nickname: String!
    gender: String!
    birthYear: Int!
    bio: String
    profileImageUrl: String
    mannerScore: Int!
    status: String!
    createdAt: String!
}

type SimpleUser {
    id: ID!
    nickname: String!
    profileImageUrl: String
    mannerScore: Int!
}

input RegisterUserInput {
    phoneNumber: String!
    nickname: String!
    gender: String!
    birthYear: Int!
}

input UpdateUserProfileInput {
    nickname: String
    bio: String
    profileImageUrl: String
}

extend type Query {
    me: User!
    user(userId: ID!): User
}

extend type Mutation {
    registerUser(input: RegisterUserInput!): User!
    updateUserProfile(input: UpdateUserProfileInput!): User!
    deleteAccount: Boolean!
}
```

